258→    opening.kind,
259→    opening.centerPoint,
260→    {
261→      x: opening.visibleWidth,
262→      y: opening.visibleHeight,
263→      z: getInsertThickness(opening.kind, opening.wallThickness),
264→    },
265→    opening.visibleBaseElevation,
266→    opening.angle,
267→    {
268→      sourceId: opening.sourceId,
269→      floorId: opening.metadata.floorId,
270→      wallId: opening.wallId,
271→      openingKind: opening.kind,
272→    }
