189→export function createFixture(fixtureType, x, y, options = {}) {
190→  const defaults = FIXTURE_DEFAULTS[fixtureType] || { width: 600, depth: 400 };
191→  return {
192→    id: generateId('fix'),
193→    fixtureType,
194→    x, y,
195→    width: options.width ?? defaults.width,
196→    depth: options.depth ?? defaults.depth,
197→    rotation: options.rotation ?? 0,
198→    name: options.name ?? '',
