 1→import { rotate } from './point';
 2→import { pointInPolygon } from './polygon';
 3→
 4→export function fixtureOutline(fixture) {
 5→  const hw = fixture.width / 2, hd = fixture.depth / 2;
 6→  const { x: cx, y: cy } = fixture;
 7→  const corners = [
 8→    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
 9→    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
10→  ];
11→  if (!fixture.rotation) return corners;
12→  return corners.map(p => rotate(p, { x: cx, y: cy }, fixture.rotation));
13→}
14→
15→export function fixtureContainsPoint(fixture, point) {
16→  return pointInPolygon(point, fixtureOutline(fixture));
17→}
